{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "action": "read",
        "resource": "datadog:alerts",
        "context": "incident_response_workflow"
      },
      "depends_on": []
    },
    {
      "tool": "datadog.list_alerts",
      "arguments": {
        "filter": {
          "status": "triggered",
          "priority": ["P1", "P2", "P3"]
        },
        "include_fields": ["alarm_name", "metric_name", "threshold", "current_value", "triggered_at", "service_tags", "severity"]
      },
      "depends_on": [1]
    },
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "query": "avg:system.cpu.user{*} by {service}, avg:system.mem.used{*} by {service}, sum:trace.request.errors{*} by {service}",
        "from": "now-1h",
        "to": "now",
        "resolution": "1m",
        "context": "threshold_breach_analysis"
      },
      "depends_on": [2]
    },
    {
      "tool": "file.read",
      "arguments": {
        "path": "s3://incident-logs/recent/",
        "filter": {
          "service": "$2.alerts[0].service_tags",
          "timestamp_from": "$2.alerts[0].triggered_at",
          "timestamp_to": "now",
          "log_levels": ["ERROR", "CRITICAL", "FATAL"]
        },
        "max_lines": 5000,
        "format": "json"
      },
      "depends_on": [2]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#incident-response",
        "message": ":rotating_light: *INCIDENT DETECTED — Channel Creation in Progress* :rotating_light:\n\n*Affected Service(s):* `$2.alerts[0].service_tags`\n*Alarm Name:* `$2.alerts[0].alarm_name`\n*Metric Threshold Breach:* `$2.alerts[0].metric_name` — Current: `$2.alerts[0].current_value` / Threshold: `$2.alerts[0].threshold`\n*Incident Onset (UTC):* `$2.alerts[0].triggered_at`\n*Severity:* `$2.alerts[0].severity`\n\nCreating dedicated incident channel and compiling initial assessment..."
      },
      "depends_on": [2, 3, 4]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#inc-$2.alerts[0].service_tags-$2.alerts[0].triggered_at",
        "message": ":fire: *INCIDENT INITIAL SEVERITY ASSESSMENT* :fire:\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n*🔴 Affected Service:*
